@app.route('/oauth/revoke', methods=['POST'])
def revoke_token():
    token_string = request.form.get('token')
    client_id = request.form.get('client_id')
    client_secret = request.form.get('client_secret')
    
    if not all([token_string, client_id, client_secret]):
        return jsonify({
            'error': 'invalid_request',
            'error_description': 'Missing required parameters'
        }), 400
    
    client = Client.query.filter_by(client_id=client_id).first()
    
    if not client or not client.check_client_secret(client_secret):
        return jsonify({
            'error': 'invalid_client',
            'error_description': 'Client authentication failed'
        }), 401
    
    token_hash = AccessToken.hash_token(token_string)
    token = AccessToken.query.filter_by(token_hash=token_hash, client_id=client.id).first()
    
    if token:
        token.revoked = True
        db.session.commit()
    
    return '', 200


@app.route('/oauth/introspect', methods=['POST'])
def introspect_token():
    token_string = request.form.get('token')
    client_id = request.form.get('client_id')
    client_secret = request.form.get('client_secret')
    
    if not all([token_string, client_id, client_secret]):
        return jsonify({'active': False}), 200
    
    client = Client.query.filter_by(client_id=client_id).first()
    
